  1	import * as React from 'react';
  2	import {
  3	  NooBaaBackingStoreModel,
  4	  NooBaaBucketClassModel,
  5	  NooBaaNamespaceStoreModel,
  6	} from '@odf/shared';
  7	import { LoadingInline } from '@odf/shared/generic/Loading';
  8	import { LoadingBox } from '@odf/shared/generic/status-box';
  9	import { useK8sList } from '@odf/shared/hooks/useK8sList';
 10	import {
 11	  CommonModalProps,
 12	  ModalBody,
 13	  ModalFooter,
 14	} from '@odf/shared/modals/Modal';
 15	import { getName } from '@odf/shared/selectors';
 16	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 17	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 18	import {
 19	  ActionGroup,
 20	  Alert,
 21	  Button,
 22	  Modal,
 23	  ModalVariant,
 24	} from '@patternfly/react-core';
 25	import { NamespacePolicyType } from '../../../constants';
 26	import {
 27	  BackingStoreKind,
 28	  BucketClassKind,
 29	  NamespaceStoreKind,
 30	  PlacementPolicy,
 31	} from '../../../types';
 32	import {
 33	  getBackingStoreNames,
 34	  getBackingStorePolicy,
 35	  validateDuration,
 36	} from '../../../utils';
 37	import BackingStoreSelection from '../backingstore-table';
 38	import { reducer, initialState } from '../state';
 39	import { CacheNamespaceStorePage } from '../wizard-pages/namespace-store-pages/cache-namespace-store';
 40	import { MultiNamespaceStorePage } from '../wizard-pages/namespace-store-pages/multi-namespace-store';
 41	import { SingleNamespaceStorePage } from '../wizard-pages/namespace-store-pages/single-namespace-store';
 42	import './_bs-modal.scss';
 43	
 44	const BucketClassEditModal: React.FC<BucketClassEditModalProps> = (props) => {
 45	  const { t } = useCustomTranslation();
 46	  const {
 47	    isOpen,
 48	    closeModal,
 49	    extraProps: { resource: bucketClass },
 50	  } = props;
 51	  const isNamespaceType = !!bucketClass.spec?.namespacePolicy;
 52	  const [state, dispatch] = React.useReducer(reducer, initialState);
 53	  const [data, loaded, loadError] = useK8sList<BackingStoreKind>(
 54	    NooBaaBackingStoreModel,
 55	    bucketClass.metadata.namespace
 56	  );
 57	
 58	  const [nsData, nsLoaded, nsLoadErr] = useK8sList<NamespaceStoreKind>(
 59	    NooBaaNamespaceStoreModel,
 60	    bucketClass.metadata.namespace
 61	  );
 62	
 63	  const [inProgress, setProgress] = React.useState(false);
 64	  const [error, setError] = React.useState('');
 65	
 66	  const policyA = getBackingStorePolicy(bucketClass, 0);
 67	  const policyB = getBackingStorePolicy(bucketClass, 1);
 68	
 69	  const getNamespaceStorePage = () => {
 70	    switch (state.namespacePolicyType) {
 71	      case NamespacePolicyType.SINGLE:
 72	        return (
 73	          <SingleNamespaceStorePage
 74	            hideCreateNamespaceStore
 75	            state={state}
 76	            dispatch={dispatch}
 77	            namespace={bucketClass.metadata.namespace}
 78	          />
 79	        );
 80	      case NamespacePolicyType.CACHE:
 81	        return (
 82	          <CacheNamespaceStorePage
 83	            hideCreateNamespaceStore
 84	            state={state}
 85	            dispatch={dispatch}
 86	            namespace={bucketClass.metadata.namespace}
 87	          />
 88	        );
 89	      case NamespacePolicyType.MULTI:
 90	        return (
 91	          <MultiNamespaceStorePage
 92	            hideCreateNamespaceStore
 93	            state={state}
 94	            dispatch={dispatch}
 95	            namespace={bucketClass.metadata.namespace}
 96	          />
 97	        );
 98	      default:
 99	        return null;
100	    }
101	  };
102	
103	  // Resolve to BackingStore Objects from Name
104	  React.useEffect(() => {
105	    if (!isNamespaceType && loaded && !loadError) {
106	      const bsNamesTier1 = getBackingStoreNames(bucketClass, 0);
107	      const bsNamesTier2 = getBackingStoreNames(bucketClass, 1);
108	      const bsTier1 = data.filter((item) =>
109	        bsNamesTier1.includes(getName(item))
110	      );
111	      const bsTier2 = data.filter((item) =>
112	        bsNamesTier2.includes(getName(item))
113	      );
114	      dispatch({ type: 'setBackingStoreTier1', value: bsTier1 });
115	      dispatch({ type: 'setBackingStoreTier2', value: bsTier2 });
116	    }
117	  }, [data, loaded, loadError, bucketClass, isNamespaceType]);
118	
119	  React.useEffect(() => {
120	    if (isNamespaceType && nsLoaded && !nsLoadErr) {
121	      dispatch({
122	        type: 'setNamespacePolicyType',
123	        value: bucketClass.spec?.namespacePolicy.type,
124	      });
125	      if (
126	        bucketClass.spec?.namespacePolicy.type === NamespacePolicyType.SINGLE
127	      ) {
128	        const singleNS = nsData.find(
129	          (item) =>
130	            getName(item) === bucketClass.spec.namespacePolicy.single.resource
131	        );
132	        dispatch({ type: 'setWriteNamespaceStore', value: [singleNS] });
133	        dispatch({ type: 'setReadNamespaceStore', value: [singleNS] });
134	      }
135	      if (
136	        bucketClass.spec?.namespacePolicy.type === NamespacePolicyType.MULTI
137	      ) {
138	        const writeNS = nsData.find(
139	          (item) =>
140	            getName(item) ===
141	            bucketClass.spec.namespacePolicy.multi.writeResource
142	        );
143	        const readNS = nsData.filter((item) =>
144	          bucketClass.spec.namespacePolicy.multi.readResources.includes(
145	            getName(item)
146	          )
147	        );
148	        dispatch({ type: 'setWriteNamespaceStore', value: [writeNS] });
149	        dispatch({ type: 'setReadNamespaceStore', value: readNS });
150	      }
151	      if (
152	        bucketClass.spec?.namespacePolicy.type === NamespacePolicyType.CACHE
153	      ) {
154	        const hubNS = nsData.find(
155	          (item) =>
156	            getName(item) === bucketClass.spec.namespacePolicy.cache.hubResource
157	        );
158	        const cacheBS = data.find((item) =>
159	          bucketClass.spec.placementPolicy.tiers[0].backingStores.includes(
160	            getName(item)
161	          )
162	        );
163	        dispatch({ type: 'setHubNamespaceStore', value: hubNS });
164	        dispatch({ type: 'setCacheBackingStore', value: cacheBS });
165	      }
166	    }
167	  }, [bucketClass, nsData, nsLoaded, nsLoadErr, isNamespaceType, data]);
168	
169	  const isEnabled = (() => {
170	    const satifiesPolicyA = (() => {
171	      if (policyA === PlacementPolicy.Spread) {
172	        return state.tier1BackingStore?.length >= 1;
173	      }
174	      if (policyA === PlacementPolicy.Mirror) {
175	        return state.tier1BackingStore?.length >= 2;
176	      }
177	      return false;
178	    })();
179	    const satifiesPolicyB = policyB
180	      ? policyB === PlacementPolicy.Spread
181	        ? state.tier2BackingStore?.length >= 1
182	        : state.tier2BackingStore?.length >= 2
183	      : true;
184	    return satifiesPolicyA && satifiesPolicyB;
185	  })();
186	
187	  const isEnabledNS = () => {
188	    if (state.namespacePolicyType === NamespacePolicyType.SINGLE) {
189	      return (
190	        state.readNamespaceStore.length === 1 &&
191	        state.writeNamespaceStore.length === 1
192	      );
193	    }
194	    if (state.namespacePolicyType === NamespacePolicyType.MULTI) {
195	      return (
196	        state.readNamespaceStore.length >= 1 &&
197	        state.writeNamespaceStore.length === 1
198	      );
199	    }
200	    if (state.namespacePolicyType === NamespacePolicyType.CACHE) {
201	      return (
202	        !!state.hubNamespaceStore &&
203	        !!state.cacheBackingStore &&
204	        validateDuration(state.timeToLive)
205	      );
206	    }
207	    return false;
208	  };
209	
210	  const onSubmit = () => {
211	    setProgress(true);
212	    if (!isNamespaceType) {
213	      bucketClass.spec.placementPolicy.tiers[0].backingStores =
214	        state.tier1BackingStore.map(getName);
215	      if (policyB?.length) {
216	        bucketClass.spec.placementPolicy.tiers[1].backingStores =
217	          state.tier2BackingStore.map(getName);
218	      }
219	    } else {
220	      switch (state.namespacePolicyType) {
221	        case NamespacePolicyType.SINGLE:
222	          bucketClass.spec.namespacePolicy.single.resource = getName(
223	            state.readNamespaceStore[0]
224	          );
225	          break;
226	        case NamespacePolicyType.MULTI:
227	          bucketClass.spec.namespacePolicy.multi.writeResource = getName(
228	            state.writeNamespaceStore[0]
229	          );
230	          bucketClass.spec.namespacePolicy.multi.readResources =
231	            state.readNamespaceStore.map(getName);
232	          break;
233	        case NamespacePolicyType.CACHE:
234	          bucketClass.spec.namespacePolicy.cache.hubResource = getName(
235	            state.hubNamespaceStore
236	          );
237	          bucketClass.spec.namespacePolicy.cache.caching.ttl = state.timeToLive;
238	          bucketClass.spec.placementPolicy.tiers[0].backingStores = [
239	            getName(state.cacheBackingStore),
240	          ];
241	          break;
242	        default:
243	      }
244	    }
245	
246	    k8sUpdate({
247	      model: NooBaaBucketClassModel,
248	      name: getName(bucketClass),
249	      data: bucketClass,
250	    })
251	      .then(() => {
252	        setProgress(false);
253	        closeModal();
254	      })
255	      .catch((err) => {
256	        setError(err);
257	      });
258	  };
259	  return (
260	    <Modal
261	      title={t('Edit BucketClass Resource')}
262	      isOpen={isOpen}
263	      variant={ModalVariant.medium}
264	      onClose={closeModal}
265	    >
266	      {nsLoaded && loaded ? (
267	        <>
268	          <ModalBody className="nb-bc-modal">
269	            <p className="nb-bc-modal__text">
270	              {t(
271	                '{{storeType}} represents a storage target to be used as the underlying storage for the data in Multicloud Object Gateway buckets.',
272	                {
273	                  storeType: isNamespaceType
274	                    ? t('NamespaceStore')
275	                    : t('BackingStore'),
276	                }
277	              )}
278	            </p>
279	            {!isNamespaceType ? (
280	              <BackingStoreSelection
281	                tier1Policy={policyA}
282	                tier2Policy={policyB}
283	                selectedTierA={state.tier1BackingStore}
284	                selectedTierB={state.tier2BackingStore}
285	                setSelectedTierA={(selectedA) =>
286	                  dispatch({ type: 'setBackingStoreTier1', value: selectedA })
287	                }
288	                setSelectedTierB={(selectedB) =>
289	                  dispatch({ type: 'setBackingStoreTier2', value: selectedB })
290	                }
291	                hideCreateBackingStore
292	              />
293	            ) : (
294	              getNamespaceStorePage()
295	            )}
296	            {error && (
297	              <Alert isInline variant="danger" title={t('An error occurred')}>
298	                {(error as any)?.message}
299	              </Alert>
300	            )}
301	          </ModalBody>
302	          <ModalFooter>
303	            <ActionGroup>
304	              <Button
305	                onClick={closeModal}
306	                aria-label={t('Cancel')}
307	                variant="secondary"
308	              >
309	                {t('Cancel')}
310	              </Button>
311	              {!inProgress ? (
312	                <Button
313	                  onClick={onSubmit}
314	                  aria-label={t('Save')}
315	                  type="submit"
316	                  className="nb-edit-modal__save-btn"
317	                  isDisabled={isNamespaceType ? !isEnabledNS() : !isEnabled}
318	                >
319	                  {t('Save')}
320	                </Button>
321	              ) : (
322	                <LoadingInline />
323	              )}
324	            </ActionGroup>
325	          </ModalFooter>
326	        </>
327	      ) : (
328	        <LoadingBox />
329	      )}
330	    </Modal>
331	  );
332	};
333	
334	export default BucketClassEditModal;
335	
336	type BucketClassEditModalProps = CommonModalProps<{
337	  resource: BucketClassKind;
338	}>;

